head.script:
        scwin.g_sUserId = "";
        scwin.vAuthYn = "N";
        scwin.closeYm = "";
        scwin.stdYm = "";
        /** ***********************************************************************
         *  화면에서 기본 로딩시 발생하는 함수 START
         ************************************************************************ */
        //-------------------------------------------------------------------------
        // 화면 로딩시 호출 되는 함수
        //------------------------------------------------------------------------- 
        scwin.onpageload = function() {
            scwin.g_sUserId = $c.data.getMemInfo("empNo");
            scwin.vCurDate  = $c.date.getServerDateTime();
            scwin.strStdDt  = scwin.vCurDate.substring(0, 6);
            scwin.params = $c.data.getParameter();
            if (scwin.params != null) {
                scwin.closeYm = scwin.params["closeYm"] || "";
                scwin.stdYm   = scwin.params["stdYm"  ] || "";
            }

            ds_search .set("clsCd", "2");
            ed_closeYm.setValue(scwin.strStdDt);

            scwin.f_befMonth();

            $c.gus.cfDisableObjects([ed_stdYm]);

            if (scwin.closeYm.trim() != "") {
                ed_closeYm.setValue(scwin.closeYm);
                ed_stdYm.setValue(scwin.stdYm);
                scwin.f_Retrieve();
                $c.gus.cfDisableObjects([btn_save, btn_saveRamt]);
            }
        };
        //-------------------------------------------------------------------------
        // 화면 에 UDC 컴포넌트가 모두 로딩 완료시 호출 되는 함수
        //------------------------------------------------------------------------- 
        scwin.onUdcCompleted = async function() {
            let codeOptions = [
                { grpCd: "ZZ006", compID: "lc_crcCd,lc_ramtCrcCd,gr_additionalValue:crcCd" },
                { grpCd: "IL111", compID: "gr_masterList:additionalKndCd,gr_additionalValue:gubun" },
                { grpCd: "IL112", compID: "gr_additionalValue:additionalKndCd" }
            ];
            await scwin.callBackFntoPromise($c.data.setCommonCode,codeOptions);
            lc_crcCd.setValue("USD");      // 통화 단위  'USD' 변경
            lc_ramtCrcCd.setValue("USD");  // 통화 단위  'USD' 변경
            await scwin.f_getRamt();
            scwin.f_retrieveAuth();
        };
        /** ***********************************************************************
         *  화면에서 기본 로딩시 발생하는 함수 END
         ************************************************************************ */

        scwin.f_retrieveAuth = async function() {
            const params = {
                sysCd   : "CommonEBC" , 
                queryId : "retrieveBorrowAcqKindInfo" ,
                param1  : "IL110" ,
                param2  : scwin.g_sUserId  /* '243030' scwin.g_sUserId */
            };

            dma_auth.setJSON(params);
            const result = await $c.sbm.execute(sbm_auth);
            if(result.responseJSON.GAUCE) {
                ds_auth.setJSON(result.responseJSON.GAUCE);
                if(ds_auth.getRowCount() != 0) {
                    $c.gus.cfEnableObjects([btn_saveRamt, lc_ramtCrcCd, ed_ramt]);
                    scwin.vAuthYn = "Y";
                } else {
                    $c.gus.cfDisableObjects([btn_saveRamt, lc_ramtCrcCd, ed_ramt]);
                    scwin.vAuthYn = "N";
                } 
            }            
        };


        scwin.f_befMonth = function() {
            const closeYm = ed_closeYm.getValue();
            const vStdYm  = $c.date.addMonth($p,closeYm + "01",-1).substring(0,6);
            ed_stdYm.setValue(vStdYm);
        };

        scwin.getLastDayOfMonth = function() {
            const lastDt = $c.date.getLastDateOfMonth(ed_stdYm.getValue());
            if (lastDt == 31) {
                gr_masterList.setColumnVisible("amt29d", true);
                gr_masterList.setColumnVisible("amt30d", true);
                gr_masterList.setColumnVisible("amt31d", true);
            } else if (lastDt == 30) {
                gr_masterList.setColumnVisible("amt29d", true);
                gr_masterList.setColumnVisible("amt30d", true);
                gr_masterList.setColumnVisible("amt31d", false);
            } else if (lastDt == 29) {
                gr_masterList.setColumnVisible("amt29d", true);
                gr_masterList.setColumnVisible("amt30d", false);
                gr_masterList.setColumnVisible("amt31d", false);
            } else if (lastDt == 28) {
                gr_masterList.setColumnVisible("amt29d", false);
                gr_masterList.setColumnVisible("amt30d", false);
                gr_masterList.setColumnVisible("amt31d", false);
            }
        };

        scwin.f_getRamt = async function() {
            const vStdYm = ed_stdYm.getValue();
            const vCrcCD = lc_ramtCrcCd.getValue();
            const param1 = " STD_YM  as COL1 "
                         + ",CRC_CD  as COL2 "
                         + ",RAMT    as COL3 "
                         + ",''      as COL4 "
                         + ",''      as COL5 "
                         + ",''      as COL6 "
                         + ",''      as COL7 "
                         + ",''      as COL8 "
                         + ",''      as COL9 "
                         + ",''      as COL10";
            const param2 = " TB_FM407 ";
            const param3 = " AND STD_YM = '" + vStdYm + "'"
                         + " AND CRC_CD = '" + vCrcCD + "'";
            const param4 = "STD_YM";
            const params = {
                sysCd   : "CommonEBC" , 
                queryId : "dinymicQueryTest" ,
                param1  ,
                param2  ,
                param3  ,
                param4   
            };

            dma_retrieveRamt.setJSON(params);
            const result = await $c.sbm.execute(sbm_retrieveRamt);
            let stdYm, crcCd, ramt;                
            if (result.responseJSON.resultDataSet[0].Msg == "SUCC" && result.responseJSON.GAUCE.length > 0) {
                const { col1, col2, col3 } = result.responseJSON.GAUCE.at(0);
                stdYm = col1;
                crcCd = col2;
                ramt  = col3;
            } else {
                stdYm = ed_stdYm.getValue();
                crcCd = lc_crcCd.getValue();
                ramt = 0;
            }
            ds_fcrcRamt.removeAll();
            ds_fcrcRamt.insertRow();
            ds_fcrcRamt.setRowPosition(0);              
            ds_fcrcRamt.setCellData(0, "stdYm", stdYm);
            ds_fcrcRamt.setCellData(0, "ramt" , ramt );
            ds_fcrcRamt.setCellData(0, "crcCd", crcCd);
        };

        //-------------------------------------------------------------------------
        // 엑셀 다운로드 함수
        //-------------------------------------------------------------------------
        scwin.f_GridToExcel = async function () {
            if ( ds_masterList.getRowCount() <= 0) {
                $c.win.alert("내역이 존재하지않습니다.");
                return false
            }
            let fileName = '전월실적분석';
            let sheetTitle = '전월실적분석';
            await $c.data.downloadGridViewExcel(gr_masterList, { fileName: fileName + ".xlsx", sheetName: sheetTitle, });
        }        

        //-------------------------------------------------------------------------
        // 기본 조회 함수
        //-------------------------------------------------------------------------
        scwin.f_Retrieve = async function() {
            let chk = await $c.gus.cfValidate([ed_stdYm]);
            if (!chk) return false;

            lc_ramtCrcCd.setValue(lc_crcCd.getValue());
            await scwin.f_getRamt();
            // 기본 그리드 조회
            const result = await $c.sbm.execute(sbm_retrieve);
            scwin.getLastDayOfMonth();
            if (ds_masterList.getRowCount() == 0) {
                await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
            }
            spa_totalRow.setValue(ds_masterList.getRowCount());
            if ( ds_masterList.getRowCount() > 0 ) {
                scwin.setGridFooter(ds_masterList.getAllJSON());
            }
            // 추가값 그리드 조회
            await $c.sbm.execute(sbm_retrieveAdditionalValue);
            spa_totalRow2.setValue(ds_additionalValue.getRowCount());
        };


        //-------------------------------------------------------------------------
        // 기초잔액 저장 함수
        //-------------------------------------------------------------------------        

        scwin.f_Save = async function() {
            if (  ds_fcrcRamt.getRowCount() == 0) {
                await $c.win.alert("데이타가 없습니다.");
                return;
            }

            if (ds_fcrcRamt.getCellData(0,"stdYm") == "") {
                ds_fcrcRamt.setCellData(0,"stdYm", ed_stdYm.getValue());
            }

            if (ds_fcrcRamt.getCellData(0,"crcCd") == "") {
                await $c.win.alert("환종을 선택하세요.");
                return;
            }

            chk = (ds_fcrcRamt.getModifiedIndex().length == 0);
            if(chk){
                $c.win.alert("변경된 사항이 없습니다.");
                return;
            }

            const result = await $c.sbm.execute(sbm_save);
            if(result.responseJSON.resultDataSet[0].Code == 0) {
                await $c.gus.cfAlertMsg("기초잔액이 저장되었습니다.");
                scwin.f_Retrieve();
            } else {
                if(result.responseJSON.resultDataSet[1] != null && result.responseJSON.resultDataSet[1].Msg != null && result.responseJSON.resultDataSet[1].Msg != "") {
                    $c.win.alert(result.responseJSON.resultDataSet[1].Msg);
                }
            }            
        };
        //-------------------------------------------------------------------------
        // 추가값 그리드 행추가
        //-------------------------------------------------------------------------        
        scwin.f_Add_gr_additionalValue = function() {
            $c.data.insertRow(gr_additionalValue);
            let row = ds_additionalValue.getRowPosition();

            ds_additionalValue.setCellData(row, "crcCd", "USD");
            ds_additionalValue.setCellData(row, "clsCd", "2");
        };
        //-------------------------------------------------------------------------
        // 추가값 그리드에 데이터 저장 함수
        //------------------------------------------------------------------------- 
        scwin.f_SaveAdditionalValue = async function() {
            let chk = await $c.gus.cfValidate([gr_additionalValue]);
            if (!chk) return false;

            if (ds_additionalValue.getRowCount() == 0) {
                await $c.win.alert("데이타가 없습니다.");
                return;
            }

            chk = (ds_additionalValue.getModifiedIndex().length == 0);
            if(chk){
                await $c.win.alert("변경된 사항이 없습니다.");
                return;
            }

            for (let i = 0; i < ds_additionalValue.getRowCount(); i++) {
                let vStdDt = ds_additionalValue.getCellData(i, "stdDt").substring(0, 6);

                if (vStdDt != ed_stdYm.getValue()) {
                    await $c.win.alert((i + 1) + "행의 날짜는 기준년월의 월과 같아야 합니다.");
                    return;
                }

                if (ds_additionalValue.getCellData(i, "additionalKndCd") == "") {
                    await $c.win.alert((i + 1) + "행의 구분값을 입력하세요");
                    return;
                }
            }
            await $c.sbm.execute(sbm_saveAdditionalValue);
            await $c.win.alert("추가값이 저장되었습니다.");
            scwin.f_Retrieve();            
        };


        /** ***********************************************************************
         *  화면에서 호출되는 컴포넌트의 이벤트 관련 함수 정의  START 
         ************************************************************************ */
        //-------------------------------------------------------------------------
        // 조회 버튼 클릭 함수.
        //------------------------------------------------------------------------- 
        scwin.btn_retrieve_onclick = function(e) {
            scwin.f_Retrieve();
        };

        //-------------------------------------------------------------------------
        // 기초잔액 저장 버튼 클릭 함수.
        //------------------------------------------------------------------------- 
        scwin.btn_saveRamt_onclick = function(e) {
            scwin.f_Save();
        };

        //-------------------------------------------------------------------------
        // 추가값 그리드 추가값 저장 버튼 클릭 함수.
        //------------------------------------------------------------------------- 
        scwin.btn_save_onclick = function(e) {
            scwin.f_SaveAdditionalValue();
        };

        scwin.ds_fcrcRamt_ondataload = function () {
            ds_fcrcRamt.setRowPosition(0);
        };

        scwin.clntPopupCallBackFn = function(resultParam) {
            const rowIndex = gr_additionalValue.getFocusedRowIndex();
            if ( resultParam.at(0) != "N/A" ) {
                const [clntNo, clntNm] = resultParam;
                ds_additionalValue.setCellData(rowIndex, "clntNo", clntNo);
                ds_additionalValue.setCellData(rowIndex, "clntNm", clntNm);
            } else {
               const clntNm = ds_additionalValue.getCellData(rowIndex, "clntNm");
            }
        }

        //-------------------------------------------------------------------------
        // 추가값 그리드의 cell 클릭시 호출 하는 함수.
        //-------------------------------------------------------------------------  
        scwin.gr_additionalValue_oncellclick = function(rowIndex, columnIndex, columnId) {
            if (ds_additionalValue.getRowStatus(rowIndex) == "C") {
                gr_additionalValue.setColumnReadOnly("additionalKndCd", false);
                gr_additionalValue.setColumnReadOnly("crcCd", false);
                gr_additionalValue.setColumnReadOnly("stdDt", false);
                gr_additionalValue.setColumnReadOnly("clntNo", false);
            } else {
                gr_additionalValue.setColumnReadOnly("additionalKndCd", true);
                gr_additionalValue.setColumnReadOnly("crcCd", true);
                gr_additionalValue.setColumnReadOnly("stdDt", false);
                gr_additionalValue.setColumnReadOnly("clntNo", true);
            }
        };
        //-------------------------------------------------------------------------
        // gr_additionalValue 그리드 icon 클릭시 호출되는 함수
        //-------------------------------------------------------------------------  
        /*
        scwin.gr_additionalValue_ontextimageclick = function(rowIndex, columnIndex) {
            const columnId = gr_additionalValue.getColumnID(columnIndex);

            if (columnId == "clntNo") {
                const clntNo = ds_additionalValue.getCellData(rowIndex , columnId);
                const clntNm = "";
                ds_additionalValue.setCellData(rowIndex , columnId , "");
                ds_additionalValue.setCellData(rowIndex , "clntNm" , "");
                scwin.f_PopUpGrid({ clntNo,clntNm });
            }
        };

        */
        //-------------------------------------------------------------------------
        // gr_additionalValue 그리드 cell 값변경시 호출되는 함수
        // ontextimageclick 두번호출 
        // gr_additionalValue_onviewchange 작동을 안해서 
        // gr_additionalValue_onafteredit 이벤트로 대신처리 한다. 
        //------------------------------------------------------------------------- 

        scwin.gr_additionalValue_onafteredit = function (rowIndex, columnIndex, value) {
            const columnId = gr_additionalValue.getColumnID(columnIndex);
            if (columnId == "clntNo") {
                const clntNo = ds_additionalValue.getCellData(rowIndex , columnId);
                const clntNm = "";
                ds_additionalValue.setCellData(rowIndex , columnId , "");
                ds_additionalValue.setCellData(rowIndex , "clntNm" , "");
                scwin.f_PopUpGrid({ clntNo,clntNm });
            }
        };
/*        
*/
        //-------------------------------------------------------------------------
        // 추가값 DataList의 column값 변경시 호출하는 함수.
        //-------------------------------------------------------------------------  
        scwin.ds_additionalValue_oncelldatachange = function(info) {
            let rowIndex = info.rowIndex;
            let colId = info.colID;

            if (colId == "clntNo") {

            } else if (colId == "additionalKndCd") {
                let kndCd = ds_additionalValue.getCellData(rowIndex, "additionalKndCd");
                if (kndCd == "1" || kndCd == "2" || kndCd == "3") {
                    ds_additionalValue.setCellData(rowIndex, "gubun", "1");
                } else if (kndCd == "4" || kndCd == "5") {
                    ds_additionalValue.setCellData(rowIndex, "gubun", "2");
                }
            }
        };

        //-------------------------------------------------------------------------
        // 기초잔액 환종 리스트 콤보 값 변경시 호출되는 함수.
        //-------------------------------------------------------------------------   
        scwin.lc_ramtCrcCd_onchange = function(e) {
            scwin.f_getRamt();
        };
        //-------------------------------------------------------------------------
        // 작성년월 값 변경시 호출되는 함수.
        //-------------------------------------------------------------------------   
        scwin.ed_closeYm_onchange = function(e) {
            scwin.f_befMonth();
        };
        /** ***********************************************************************
         *  화면에서 호출되는 컴포넌트의 이벤트 관련 함수 정의  END 
         ************************************************************************ */

        /** ***********************************************************************
         *  ETC 해당 프로그램에서 사용되는 함수 정의 START
         ************************************************************************ */
         scwin.f_PopUpGrid = function(_options = {}){

            // pCallback, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, pW, pH, pTop, pLeft, pExistTF, pAllSearchTF, 
            // pWtitleSearch, pNoDataCloseTF, tmpDataSet, pCodeObj, pNameObj
            const options = Object.assign({
                  gubun            : _options.gubun           || "clntPopup" 
                , pCode            : _options.clntNo          || ""
                , pName            : _options.clntNm          || ""
                , pWinCloseTF      : _options.pWinCloseTF     || 'T'
                , pDispCnt         : _options.pDispCnt        || '5'
                , pTitle           : _options.pTitle          || "거래처코드,거래처명" 
                , pWidth           : _options.pWidth          ||  "130,300"
                , pHidden          : _options.pHidden         || "3,4,5,6,7,8,9,10"
                , pWhere           : _options.pWhere          || null // "100"
                , pW               : _options.pW              || "500"
                , pH               : _options.pH              || "500"
                , pTop             : _options.pTop            || null
                , pLeft            : _options.pLeft           || null
                , pExistTF         : _options.pExistTF        || null
                , pAllSearchTF     : _options.pAllSearchTF    || 'F'
                , pWtitleSearch    : _options.pWtitleSearch   || null //"거래처 팝업,거래처코드,거래처명"
                , pNoDataCloseTF   : _options.pNoDataCloseTF  || "F"
            },_options);

            switch(options.gubun) {
                case "clntPopup" : // 거래처 팝업
                    udc_clntNo.cfCommonPopUp(
                          scwin.clntPopupCallBackFn
                        , options.pCode
                        , options.pName
                        , options.pWinCloseTF
                        , options.pDispCnt
                        , options.pTitle
                        , options.pWidth
                        , options.pHidden 
                        , options.pWhere
                        , options.pW
                        , options.pH
                        , options.pTop
                        , options.pLeft
                        , options.pExistTF
                        , options.pAllSearchTF
                        , options.pWtitleSearch
                        , options.pNoDataCloseTF 
                    ); // 거래처			
                    break;
            }
        }

        //-------------------------------------------------------------------------
        // 그리드에 footer를 설정하는 함수 
        //-------------------------------------------------------------------------         
        scwin.setGridFooter = function(masterList = []) {
            if ( masterList.length == 0 ) return;
            const lastDay= $c.date.getLastDateOfMonth($p,ed_stdYm.getValue());
            const footerMap = {};
            const beforeKeyInfo = ["rsltsAmt", "planAmt", "sumAmt"];
            const beforeMap = {};
            masterList.forEach(master=>{
                for(let i = 1 ; i <= lastDay; i ++ ) {
                    if ( !footerMap[`amt${i}d`] ) {
                        footerMap[`amt${i}d`] = 0;
                    }
                    footerMap[`amt${i}d`] +=  ( master["additionalKndCd"] == "1" ? 1 : -1 ) * Number(master[`amt${i}d`]) ;
                }
                beforeKeyInfo.map(key=>{
                    if ( !beforeMap[key] ) {
                        beforeMap[key] = 0;
                    }
                    beforeMap[key] += ( master["additionalKndCd"] == "1" ? 1 : -1 ) * Number(master[key]) ;
                });

            });
            const stdRamt = Number(ed_ramt.getValue()||0);

            for(let i = lastDay ; i >= 1; i -- ) {
                let amtSum = 0;
                for( let j = 1 ; j < i ; j ++ ) {
                    amtSum += footerMap[`amt${j}d`];
                }
                footerMap[`amt${i}d`] += amtSum + stdRamt;
            }
            for(let i = lastDay ; i >= 1; i -- ) {
                gr_masterList.setFooterData(`amt${i}d`, footerMap[`amt${i}d`]);
            }
            beforeKeyInfo.map(key=>{
                gr_masterList.setFooterData(key, stdRamt + beforeMap[key]);
            }); 
        }         
        //-------------------------------------------------------------------------
        // Submission에서 submiterror에 대응하는 기본 함수 
        //-------------------------------------------------------------------------         

        scwin.sbm_submiterror = function(e) {
            $c.gus.cfShowError(e);
        };

        //-------------------------------------------------------------------------
        // callback함수를 Promise로 전환 하는 함수.
        //-------------------------------------------------------------------------         
        scwin.callBackFntoPromise = function(callFunction,...param){
            return new Promise(function(resolve,reject){
                try {
                    callFunction($p,...param,function(rtnParam){
                        resolve(rtnParam);
                    });
                } catch (e) {
                    reject(e)
                }
            });
        };
        /** ***********************************************************************
         *  ETC 해당 프로그램에서 사용되는 함수 정의 END
         ************************************************************************ */
